return (async () => {
  const input = $input.first().json;
  const body = input.body || input;
  const creator = body.creator || {};
  const env = $env || {};
  const https = require('https');
  const http = require('http');
  const { URL } = require('url');
  const now = new Date().toISOString();
  const mode = body.mode || (body.action === 'classify_reply' ? 'classify_reply' : 'draft');

  if (body.allowSend === true || body.dryRun === false || body.action === 'record_sent') {
    return [{ json: { ok: false, status: 'blocked', queueId: body.queueId || '', source: 'creator-ai-router', dryRun: true, allowSend: false, message: 'This AI webhook only creates drafts or classifies replies. It never sends outreach.', updatedAt: now } }];
  }

  if (!env.DEEPSEEK_API_KEY) {
    return [{ json: { ok: false, status: 'needs_ai_config', queueId: body.queueId || '', source: 'deepseek', dryRun: true, allowSend: false, message: 'DEEPSEEK_API_KEY is not configured in n8n.', updatedAt: now } }];
  }

  function clean(value) { return String(value ?? '').trim(); }
  function compact(record) { return Object.fromEntries(Object.entries(record).filter(([, value]) => value !== undefined && value !== null && value !== '')); }
  function parseJson(value) {
    const raw = clean(value).replace(/^```(?:json)?/i, '').replace(/```$/i, '').trim();
    try { return JSON.parse(raw); } catch {}
    const match = raw.match(/\{[\s\S]*\}/);
    if (match) { try { return JSON.parse(match[0]); } catch {} }
    return {};
  }

  function requestJson(targetUrl, options = {}) {
    return new Promise((resolve, reject) => {
      const parsedUrl = new URL(targetUrl);
      const client = parsedUrl.protocol === 'https:' ? https : http;
      const requestBody = options.body ? String(options.body) : '';
      const request = client.request(parsedUrl, {
        method: options.method || 'GET',
        headers: {
          ...(options.headers || {}),
          ...(requestBody ? { 'Content-Length': Buffer.byteLength(requestBody) } : {}),
        },
      }, (response) => {
        let responseBody = '';
        response.setEncoding('utf8');
        response.on('data', (chunk) => { responseBody += chunk; });
        response.on('end', () => {
          let data = {};
          try { data = responseBody ? JSON.parse(responseBody) : {}; } catch { data = { raw: responseBody }; }
          resolve({ statusCode: response.statusCode || 0, data });
        });
      });
      request.on('error', reject);
      if (requestBody) request.write(requestBody);
      request.end();
    });
  }

  const baseUrl = (env.DEEPSEEK_BASE_URL || 'https://api.deepseek.com').replace(/\/$/, '');
  const model = env.DEEPSEEK_MODEL || 'deepseek-v4-flash';
  const handle = clean(creator.handle).replace(/^@/, '');
  const name = clean(creator.displayName) || handle || 'creator';
  const keywords = Array.isArray(creator.matchedKeywords) ? creator.matchedKeywords.slice(0, 8) : [];
  const metrics = creator.metrics || {};
  const evidence = creator.evidence || {};
  const videos = Array.isArray(evidence.recentVideos) ? evidence.recentVideos.slice(0, 5) : [];
  const facts = [
    `Name: ${name}`,
    handle ? `TikTok: @${handle}` : '',
    creator.profileUrl ? `Profile: ${creator.profileUrl}` : '',
    creator.description ? `Bio/description: ${creator.description}` : '',
    keywords.length ? `Matched keywords: ${keywords.join(', ')}` : '',
    metrics.followers ? `Followers: ${metrics.followers}` : '',
    metrics.stableVideoCount !== undefined ? `Recent videos over 1000 views: ${metrics.stableVideoCount}/10` : '',
    metrics.daysSinceLastPost !== undefined ? `Days since last post: ${metrics.daysSinceLastPost}` : '',
    metrics.productVideoCount !== undefined ? `Product-associated videos: ${metrics.productVideoCount}` : '',
    videos.length ? `Recent video evidence: ${videos.map((video) => `${video.title || video.videoId || 'video'} (${video.views || 0} views)`).join('; ')}` : '',
  ].filter(Boolean).join('\n');

  const system = 'You are a US creator partnership operator for a Black women hair product seller. Use only facts in the input. Do not invent email, phone, price, guarantees, shipping promises, or previous relationship. For draft mode, return compact JSON with subject and draft. For classify_reply mode, return compact JSON with replyIntent, recommendedNextStep, riskFlags, and shortReason.';
  const user = mode === 'classify_reply'
    ? [`Classify this creator reply and choose the next CRM step.`, facts, `Reply text: ${clean(body.reply?.content || body.message?.reply || body.content)}`].join('\n\n')
    : [`Write a first outreach draft for this creator.`, facts, `Offer: free product plus paid collaboration plus commission. Main deliverable: TikTok Shop video for drawstring ponytail, half wig, crochet hair, or braids products. Keep it natural, concise, respectful, and under 140 words. Output JSON only: {"subject":"...","draft":"..."}`].join('\n\n');

  try {
    const response = await requestJson(`${baseUrl}/chat/completions`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json', Authorization: `Bearer ${env.DEEPSEEK_API_KEY}` },
      body: JSON.stringify({ model, temperature: mode === 'classify_reply' ? 0.2 : 0.7, max_tokens: mode === 'classify_reply' ? 350 : 600, messages: [{ role: 'system', content: system }, { role: 'user', content: user }] }),
    });
    const data = response.data || {};
    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw new Error(data?.error?.message || `DeepSeek request failed with HTTP ${response.statusCode}`);
    }
    const content = clean(data?.choices?.[0]?.message?.content);
    const parsed = parseJson(content);

    if (mode === 'classify_reply') {
      return [{ json: { ok: true, queueId: body.queueId || '', status: 'reply_classified', source: 'deepseek', provider: 'deepseek', model, replyIntent: parsed.replyIntent || parsed.intent || 'needs_review', recommendedNextStep: parsed.recommendedNextStep || 'human_review', riskFlags: parsed.riskFlags || [], shortReason: parsed.shortReason || content, dryRun: true, allowSend: false, updatedAt: now } }];
    }

    const draft = clean(parsed.draft) || content;
    const subject = clean(parsed.subject) || `Collaboration with ${name}`;
    if (!draft) {
      throw new Error('DeepSeek returned an empty draft.');
    }

    return [{ json: compact({ ok: true, queueId: body.queueId || '', status: 'draft_ready', source: 'deepseek', provider: 'deepseek', model, subject, draft, message: draft, dryRun: true, allowSend: false, creatorId: creator.id || '', creatorHandle: handle, videosChecked: videos.length, updatedAt: now }) }];
  } catch (error) {
    return [{ json: { ok: false, queueId: body.queueId || '', status: 'ai_failed', source: 'deepseek', provider: 'deepseek', model, dryRun: true, allowSend: false, message: error instanceof Error ? error.message : 'DeepSeek request failed', updatedAt: now } }];
  }
})();
